SELECT etfs.etf_name, investment_focuses.focus_name
FROM etfs
JOIN investment_focuses ON etfs.investment_focus_id = investment_focuses.focus_id;

SELECT clients.client_name, portfolios.portfolio_name
FROM clients
LEFT JOIN portfolios ON clients.client_id = portfolios.client_id;

SELECT COUNT(DISTINCT etf_id)
FROM etf_sustainability
WHERE sustainability_score IN ('A', 'AA');

SELECT COUNT(DISTINCT e.etf_id)
FROM etfs e
JOIN performance p ON e.etf_id = p.etf_id
WHERE p.return > (
    SELECT AVG(return) FROM performance
);

SELECT COUNT(*)
FROM etf_performance_metrics e
WHERE e.etf_id = 1 AND e.metric_name = 'Sharpe Ratio';

SELECT etf_name, return_1y
FROM etfs
WHERE return_1y = (SELECT MAX(return_1y) FROM etfs);

SELECT etfs.etf_name, etf_sustainability.sustainability_score
FROM etfs
JOIN etf_sustainability ON etfs.etf_id = etf_sustainability.etf_id;
